}

-- Millimeter dimensions for cards
Dim.mm_upgrade_width = 41
Dim.mm_upgrade_height = 63
Dim.mm_pilot_width = 63.5
Dim.mm_pilot_height = 88

Dim.mm_ship_scale = vector(0.629, 0.629, 0.629)

